All names are clear and descriptive. No naming improvements needed.

## Step 2: Calculate Initial APP Mass

```typescript
// Implementation functions only
function hasCursedItem(items: QuoteItem[]): boolean {
  return items.some(item => item.cursed);
}

function hasHighEnchantment(items: QuoteItem[]): boolean {
  return items.some(item => item.enchantment !== undefined && item.enchantment >= 5);
}

function hasCursedAndEnchanted(items: QuoteItem[]): boolean {
  return items.some(item => item.cursed && item.enchantment !== undefined && item.enchantment >= 5);
}

function calculateItemPremium(item: QuoteItem): number {
  const basePremium = getItemBasePremium(item.type);
  if (basePremium === undefined) {
    throw new Error(`Unknown item type: ${item.type}`);
  }
  let premium = basePremium;
  if (item.cursed) {
    premium += basePremium * 0.5;
  }
  if (item.enchantment !== undefined && item.enchantment >= 5) {
    premium += basePremium * 0.3;
  }
  return premium;
}

export function createQuote(items: unknown[]): number {
  const quoteItems = items as QuoteItem[];
  if (quoteItems.length === 0) {
    return PROCESSING_FEE;
  }
  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
  const hasEnchantedOnly = hasHighEnchantment(quoteItems) && !hasCursedItem(quoteItems);
  const hasCursedAndEnch = hasCursedAndEnchanted(quoteItems);
  const fee = hasEnchantedOnly ? 0 : (hasCursedAndEnch ? PROCESSING_FEE : (hasCursedItem(quoteItems) ? 10 : PROCESSING_FEE));
  return totalPremium + fee;
}
```

